module pulse_generator (
    input clk,
    input reset,
    output reg pulse
);

    reg [1:0] cycle_counter;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            cycle_counter <= 0;
            pulse <= 0;
        end else if (cycle_counter == 2) begin
            pulse <= 1;
            cycle_counter <= 0;
        end else begin
            cycle_counter <= cycle_counter + 1;
            pulse <= 0;
        end
    end
endmodule
